    def _run(self):
        if not self._db.connected:
            messagebox.showerror("Not Connected", "Please connect to a plant first.")
            return

        self._run_btn.config(state="disabled", text="Running...")
        self._overall_lbl.config(text="Running checks...", fg=PALETTE["text_dim"])
        self._cards[q_query_1].set_running()
        self._cards[q_query_2].set_running()
        self._cards[q_query_3].set_running()
        self._cards[q_query_5].set_running()
        self._cards[q_query_4].set_running()

        self._log.banner("Pick Detail Tracking")

        import threading as _threading
        total_queries = 5
        completed     = [0]
        results_store = {}
        lock          = _threading.Lock()

        def _finish_one(qry, result):
            with lock:
                results_store[qry] = result
                completed[0] += 1
                done = completed[0]
            self.after(0, lambda q=qry, r=result: self._apply_result(q, r))
            if done == total_queries:
                self.after(0, lambda: self._finish(results_store))

        def _make_skipped(reason="Skipped"):
            from common import QueryResult
            r = QueryResult()
            r.status  = "_skipped"
            r.headline = reason
            return r

        def _thread_0():
            import threading as _t
            _rs  = {}   # query_id → QueryResult
            _dfs = {}   # TBL_KEY  → pd.DataFrame (from temp table parents)
            _rs["query_1"] = q_query_1.run(self._param_vars.get("barcode", tk.StringVar()).get().strip(), self._param_vars.get("pickid", tk.StringVar()).get().strip(), self._param_vars.get("warehouselocationid", tk.StringVar()).get().strip())
            _finish_one(q_query_1, _rs["query_1"])
            if getattr(_rs["query_1"], "dataframe", None):
                _dfs.update(_rs["query_1"].dataframe)

